fn solve(n: Int64, edges: Array[Array[Int64]], source: Int64, target: Int64, k: Int64): Int64 {
  if source == target {
    return 0
  }

  // 1. Build adjacency list
  var adj = Array[Array[Edge]].new(n)
  for edge_data in edges {
    var u = edge_data[0]
    var v = edge_data[1]
    var w = edge_data[2]

    adj[u].push(Edge(target: v, weight: w))
    adj[v].push(Edge(target: u, weight: w))
  }

  // 2. Check function: Dijkstra's algorithm to find min heavy edges
  fn check(threshold: Int64): Bool {
    // D[i] stores the minimum number of heavy edges to reach node i
    var dist = Array[Int64].new(n).fill(Int64.MAX)
    dist[source] = 0

    // O(N^2) Dijkstra implementation suitable for N <= 1000
    var visited = Array[Bool].new(n).fill(false)

    for _ in 0..n {
      // Find unvisited node u with minimum distance
      var min_dist = Int64.MAX
      var u = -1.0

      for i in 0..<n {
        if !visited[i] && dist[i] < min_dist {
          min_dist = dist[i]
          u = i.to_i64()
        }
      }

      if u == -1.0 || dist[u] > k {
        // If no reachable unvisited node, or minimum distance already exceeds K
        break
      }

      visited[u.to_i64()] = true

      if u == target {
        // Optimization: if we reached target and dist[target] <= k, we succeeded.
        return true
      }

      // Relax edges
      for edge in adj[u.to_i64()] {
        var v = edge.target
        var w = edge.weight

        // Cost is 1 if heavy (w > threshold), 0 if light (w <= threshold)
        var cost = if w > threshold { 1 } else { 0 }

        var new_dist = dist[u.to_i64()] + cost

        if new_dist <= k && new_dist < dist[v] {
          dist[v] = new_dist
        }
      }
    }

    return dist[target] <= k
  }

  // 3. Binary Search on Threshold
  // Search range: [L, R]. L=0 (minimum possible threshold), R=10^9 + 1 (guarantees all edges are light)
  var L = 0
  var R = 1_000_000_000 + 1
  var result = -1

  while L <= R {
    var M = L + (R - L) / 2

    if check(M) {
      // M works. Try for a smaller threshold.
      result = M
      R = M - 1
    } else {
      // M is too small (too many heavy edges, or no path exists even with M). Increase threshold.
      L = M + 1
    }
  }

  result
}
